  window.CYCLIFY_CYCLETIME_PRODUCTS=payload.products;
  window.cyclifyMergeSupplierProducts=function(target,page){
    const normalise=value=>String(value||"").toLowerCase().replace(/[^a-z0-9]+/g,"");
    payload.products.filter(item=>!page||item.categoryPage===page).forEach(item=>{
      const existing=target.find(product=>product.id===item.id||product.sourceHandle===item.sourceHandle||normalise(product.name)===normalise(item.name));
      if(existing){const id=existing.id;Object.assign(existing,item,{id});}
      else{target.push({...item});}
    });
    return target;
  };
